import java.io.*;
public class StaticNotSaved {
    static class Counter implements Serializable {
        static int count = 0;  // static — not serialized
        int id;
        Counter() { id = ++count; }
    }
    public static void main(String[] args) throws Exception {
        Counter.count = 0;
        Counter c = new Counter();  // id=1, count=1
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        new ObjectOutputStream(baos).writeObject(c);
        Counter.count = 99;  // simulate changed state
        Counter c2 = (Counter) new ObjectInputStream(
            new ByteArrayInputStream(baos.toByteArray())).readObject();
        System.out.println(c2.id);
        System.out.println(Counter.count);
    }
}
